// Arrow Function Toolkit

// 1. clamp: keep value within [min, max]
const clamp = (value, min, max) => {
    if (value < min) return min;
    if (value > max) return max;
    return value;
};

// 2. percentage: compute percentage rounded to 1 decimal
const percentage = (part, total) => parseFloat((part / total * 100).toFixed(1));

// 3. initials: get first letter of each word, joined with dots
// Your code here — store in const initials

console.log("Clamp:",      clamp(-5, 0, 100), clamp(150, 0, 100), clamp(75, 0, 100));
console.log("Percentage:", percentage(85, 100));
console.log("Initials:",   initials("Rahul Kumar Sharma"));

exercise.solutionCode:
const clamp = (value, min, max) => {
    if (value < min) return min;
    if (value > max) return max;
    return value;
};

const percentage = (part, total) => parseFloat((part / total * 100).toFixed(1));

const initials = fullName =>
    fullName.split(" ").map(w => w[0]).join(".");

console.log("Clamp:",      clamp(-5, 0, 100), clamp(150, 0, 100), clamp(75, 0, 100));
console.log("Percentage:", percentage(85, 100));
console.log("Initials:",   initials("Rahul Kumar Sharma"));
